import React, { useEffect, useState } from 'react';
import axios from 'axios';
import AnimatedNumber from '../../components/AnimatedNumber';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

const COLORS = ['#1a56db','#10b981','#f59e0b','#ef4444','#6366f1','#06b6d4','#ec4899','#8b5cf6'];

export default function AdminDashboard() {
  const [data, setData]     = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/admin/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data)   return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load stats</div></div>;

  const { stats, studentsByDept, studentsBySem } = data;
  const semData  = studentsBySem.map(s => ({ name: `Sem ${s._id}`, students: s.count }));
  const deptData = studentsByDept.map(d => ({ name: d.deptName || 'Unknown', value: d.count }));

  return (
    <div>
      <div className="stats-grid">
        <div className="stat-card blue">  <div className="stat-icon">👨‍🎓</div><div><div className="stat-value"><AnimatedNumber value={stats.totalStudents} /></div>  <div className="stat-label">Total Students</div></div></div>
        <div className="stat-card green"> <div className="stat-icon">👩‍🏫</div><div><div className="stat-value"><AnimatedNumber value={stats.totalFaculty} /></div>   <div className="stat-label">Faculty Members</div></div></div>
        <div className="stat-card purple"><div className="stat-icon">🧑‍💼</div><div><div className="stat-value"><AnimatedNumber value={stats.totalHods} /></div>      <div className="stat-label">HODs</div></div></div>
        <div className="stat-card yellow"><div className="stat-icon">🏢</div><div><div className="stat-value"><AnimatedNumber value={stats.totalDepartments} /></div><div className="stat-label">Departments</div></div></div>
        <div className="stat-card cyan">  <div className="stat-icon">📚</div><div><div className="stat-value"><AnimatedNumber value={stats.totalSubjects} /></div>   <div className="stat-label">Subjects</div></div></div>
        <div className="stat-card red">   <div className="stat-icon">📊</div><div><div className="stat-value"><AnimatedNumber value={stats.totalMarksEntries} /></div><div className="stat-label">Marks Entries</div></div></div>
      </div>

      {/* Charts — stack on mobile, side by side on desktop */}
      <div className="charts-grid">
        <div className="card">
          <div className="card-header"><span className="card-title">📊 Students by Semester</span></div>
          <div className="card-body">
            {semData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={semData} margin={{ top: 5, right: 10, left: -10, bottom: 5 }}>
                    <XAxis dataKey="name" tick={{ fontSize: 11 }} />
                    <YAxis allowDecimals={false} tick={{ fontSize: 11 }} />
                    <Tooltip />
                    <Bar dataKey="students" fill="#1a56db" radius={[4,4,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No student data</div></div>}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><span className="card-title">🏢 Students by Department</span></div>
          <div className="card-body">
            {deptData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart margin={{ top: 5, right: 5, left: 5, bottom: 5 }}>
                    <Pie
                      data={deptData}
                      cx="50%" cy="45%"
                      outerRadius="60%"
                      dataKey="value"
                      label={({ name, value }) => `${value}`}
                      labelLine={true}
                    >
                      {deptData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                    </Pie>
                    <Tooltip formatter={(val, name) => [val, name]} />
                    <Legend
                      layout="horizontal"
                      verticalAlign="bottom"
                      align="center"
                      wrapperStyle={{ fontSize: 11, paddingTop: 8 }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No department data</div></div>}
          </div>
        </div>
      </div>
    </div>
  );
}
